import React, { useRef, useEffect } from 'react';
import { SimulationEngine } from '../simulation/engine';
import { PathfindingMode } from '../types';

interface GameCanvasProps {
    engine: SimulationEngine;
    width: number;
    height: number;
}

const GameCanvas: React.FC<GameCanvasProps> = ({ engine, width, height }) => {
    const canvasRef = useRef<HTMLCanvasElement>(null);

    // View State stored in Ref to be accessible in render loop and event handlers without re-renders
    const viewRef = useRef({ x: 0, y: 0, scale: 1 });
    const isDragging = useRef(false);
    const lastPos = useRef({ x: 0, y: 0 });
    const lastPinchDist = useRef<number | null>(null);

    // Initialize View to Center
    useEffect(() => {
        const padding = 40;
        const availableW = width - padding;
        const availableH = height - padding;
        const worldSize = engine.config.WORLD_SIZE;

        // Calculate scale to fit world in screen
        const scale = Math.min(availableW / worldSize, availableH / worldSize);
        // Ensure some minimum scale so it doesn't look broken on huge worlds
        const safeScale = Math.max(scale, 0.05);

        viewRef.current = {
            scale: safeScale,
            x: (width - worldSize * safeScale) / 2,
            y: (height - worldSize * safeScale) / 2
        };
    }, [width, height, engine.config.WORLD_SIZE]);

    useEffect(() => {
        const canvas = canvasRef.current;
        if (!canvas) return;
        const ctx = canvas.getContext('2d');
        if (!ctx) return;

        let animationFrameId: number;

        const render = () => {
            const { x, y, scale } = viewRef.current;

            ctx.fillStyle = '#020617'; // slate-950
            ctx.fillRect(0, 0, width, height);

            ctx.save();
            ctx.translate(x, y);
            ctx.scale(scale, scale);

            // Draw Background Grid (Optional, helps visualising space)
            // ctx.strokeStyle = '#1e293b';
            // ctx.lineWidth = 1 / scale;
            // ctx.strokeRect(0, 0, engine.config.WORLD_SIZE, engine.config.WORLD_SIZE);

            // Draw Base Area (Safe zone)
            ctx.fillStyle = 'rgba(30, 41, 59, 0.8)'; // slate-800
            ctx.fillRect(engine.base.rect.x, engine.base.rect.y, engine.base.rect.w, engine.base.rect.h);

            // Draw Base Border (Glow effect)
            ctx.strokeStyle = '#3b82f6'; // blue-500
            ctx.lineWidth = 2; // Keep consistent line width? or 2/scale?
            ctx.strokeRect(engine.base.rect.x, engine.base.rect.y, engine.base.rect.w, engine.base.rect.h);

            // Draw Resources
            engine.resources.forEach(res => {
                if (res.isDeposited) {
                    ctx.fillStyle = '#64748b'; // slate-500
                } else if (res.isCarried) {
                    ctx.fillStyle = '#22d3ee'; // cyan-400
                } else {
                    ctx.fillStyle = res.color;
                }
                ctx.fillRect(res.rect.x, res.rect.y, res.rect.w, res.rect.h);
            });

            // Draw Agent Paths (APPROACH state)
            ctx.strokeStyle = 'rgba(255, 255, 255, 0.3)';
            ctx.lineWidth = 1; // Keeping 1 looks nicer when zoomed out, effectively invisible
            // To make it visible when zoomed out, maybe 1/scale but clamped

            ctx.setLineDash([4, 4]); // Dashed line

            ctx.beginPath();
            engine.agents.forEach(agent => {
                if (agent.state === 'APPROACH' && agent.targetResource) {
                    const ax = agent.rect.x + agent.rect.w / 2;
                    const ay = agent.rect.y + agent.rect.h / 2;

                    if (engine.config.PATHFINDING_MODE === PathfindingMode.A_STAR && agent.path && agent.path.length > 0) {
                        ctx.moveTo(ax, ay);
                        for(let i = agent.pathIndex; i < agent.path.length; i++) {
                            ctx.lineTo(agent.path[i].x, agent.path[i].y);
                        }
                        const tx = agent.targetResource.rect.x + agent.targetResource.rect.w / 2;
                        const ty = agent.targetResource.rect.y + agent.targetResource.rect.h / 2;
                        ctx.lineTo(tx, ty);
                    } 
                    else {
                        const tx = agent.targetResource.rect.x + agent.targetResource.rect.w / 2;
                        const ty = agent.targetResource.rect.y + agent.targetResource.rect.h / 2;
                        ctx.moveTo(ax, ay);
                        ctx.lineTo(tx, ty);
                    }
                }
            });
            ctx.stroke();
            ctx.setLineDash([]); 

            // Draw Agents
            engine.agents.forEach(agent => {
                switch (agent.state) {
                    case 'SEARCH': ctx.fillStyle = '#ef4444'; break;
                    case 'APPROACH': ctx.fillStyle = '#eab308'; break;
                    case 'RETURN': ctx.fillStyle = '#10b981'; break;
                }

                ctx.beginPath();
                ctx.roundRect(agent.rect.x, agent.rect.y, agent.rect.w, agent.rect.h, 2);
                ctx.fill();

                // Direction Indicator
                ctx.fillStyle = 'rgba(255, 255, 255, 0.9)';
                const centerX = agent.rect.x + agent.rect.w / 2;
                const centerY = agent.rect.y + agent.rect.h / 2;
                const dx = Math.sign(agent.lastMove.x) * (agent.rect.w * 0.3);
                const dy = Math.sign(agent.lastMove.y) * (agent.rect.h * 0.3);

                ctx.beginPath();
                ctx.arc(centerX + dx, centerY + dy, agent.rect.w * 0.2, 0, Math.PI * 2);
                ctx.fill();
            });

            ctx.restore();
            animationFrameId = requestAnimationFrame(render);
        };

        render();

        return () => {
            cancelAnimationFrame(animationFrameId);
        };
    }, [engine, width, height]);

    // --- Interaction Handlers ---

    const handleWheel = (e: React.WheelEvent) => {
        // Prevent default only if we are consuming the event (usually good for canvas)
        // e.preventDefault(); // React's SyntheticEvent might not support this easily for passive listeners.

        const zoomSpeed = 0.1;
        const delta = -Math.sign(e.deltaY) * zoomSpeed;
        const newScale = viewRef.current.scale * (1 + delta);
        const safeNewScale = Math.max(0.01, Math.min(newScale, 10));

        // Calculate world point under mouse before zoom
        const rect = canvasRef.current!.getBoundingClientRect();
        const mx = e.clientX - rect.left;
        const my = e.clientY - rect.top;

        const worldX = (mx - viewRef.current.x) / viewRef.current.scale;
        const worldY = (my - viewRef.current.y) / viewRef.current.scale;

        // Apply new zoom
        viewRef.current.scale = safeNewScale;

        // Adjust position so world point under mouse remains stable
        viewRef.current.x = mx - worldX * safeNewScale;
        viewRef.current.y = my - worldY * safeNewScale;
    };

    const handlePointerDown = (e: React.PointerEvent) => {
        isDragging.current = true;
        lastPos.current = { x: e.clientX, y: e.clientY };
        (e.target as HTMLElement).setPointerCapture(e.pointerId);
    };

    const handlePointerMove = (e: React.PointerEvent) => {
        if (!isDragging.current) return;

        const dx = e.clientX - lastPos.current.x;
        const dy = e.clientY - lastPos.current.y;

        viewRef.current.x += dx;
        viewRef.current.y += dy;

        lastPos.current = { x: e.clientX, y: e.clientY };
    };

    const handlePointerUp = (e: React.PointerEvent) => {
        isDragging.current = false;
        lastPinchDist.current = null; // Reset pinch
        (e.target as HTMLElement).releasePointerCapture(e.pointerId);
    };

    // Touch specific for pinch zoom
    const handleTouchMove = (e: React.TouchEvent) => {
        if (e.touches.length === 2) {
            const t1 = e.touches[0];
            const t2 = e.touches[1];
            const dist = Math.sqrt(Math.pow(t2.clientX - t1.clientX, 2) + Math.pow(t2.clientY - t1.clientY, 2));

            if (lastPinchDist.current !== null) {
                const center = {
                    x: (t1.clientX + t2.clientX) / 2,
                    y: (t1.clientY + t2.clientY) / 2
                };

                const ratio = dist / lastPinchDist.current;
                const newScale = Math.max(0.01, Math.min(viewRef.current.scale * ratio, 10));

                // Pivot around center
                const rect = canvasRef.current!.getBoundingClientRect();
                const mx = center.x - rect.left;
                const my = center.y - rect.top;

                const worldX = (mx - viewRef.current.x) / viewRef.current.scale;
                const worldY = (my - viewRef.current.y) / viewRef.current.scale;

                viewRef.current.scale = newScale;
                viewRef.current.x = mx - worldX * newScale;
                viewRef.current.y = my - worldY * newScale;
            }

            lastPinchDist.current = dist;
        }
    };

    const handleTouchEnd = () => {
        lastPinchDist.current = null;
    };

    return (
        <canvas
            ref={canvasRef}
            width={width}
            height={height}
            className="block touch-none cursor-grab active:cursor-grabbing outline-none"
            onWheel={handleWheel}
            onPointerDown={handlePointerDown}
            onPointerMove={handlePointerMove}
            onPointerUp={handlePointerUp}
            onPointerLeave={handlePointerUp}
            onTouchMove={handleTouchMove}
            onTouchEnd={handleTouchEnd}
        />
    );
};

export default GameCanvas;

import { AgentState, Rect, SimulationConfig, PathfindingMode } from '../types';

export const DefaultConfig: SimulationConfig = {
    WORLD_SIZE: 1024,
    AGENT_SPEED: 3,
    AGENT_LOS: 176,
    BASE_START_SIZE: 64,
    RESOURCE_SIZE: 8,
    AGENT_SIZE: 8,
    INITIAL_AGENTS: 3,
    INITIAL_RESOURCES: 64,
    AGENT_SPAWN_THRESHOLD: 262144,
    RESOURCE_SPAWN_CHANCE: 0.1,
    BASE_POINT_MULTIPLIER: 1.0,
    AGENT_WIGGLE: 0,
    MAX_AGENTS: 5000,
    PATHFINDING_MODE: PathfindingMode.A_STAR
};

interface Point {
    x: number;
    y: number;
}

// A* Implementation
const GRID_SIZE = 32;

class Node {
    constructor(
        public x: number,
        public y: number,
        public g: number = 0,
        public h: number = 0,
        public parent: Node | null = null
    ) {}

    get f() { return this.g + this.h; }
    get key() { return `${this.x},${this.y}`; }
}

function findPath(start: Point, end: Point, obstacle: Rect, worldSize: number): Point[] {
    const startGrid = { x: Math.floor(start.x / GRID_SIZE), y: Math.floor(start.y / GRID_SIZE) };
    const endGrid = { x: Math.floor(end.x / GRID_SIZE), y: Math.floor(end.y / GRID_SIZE) };

    // Convert obstacle to grid bounds (with padding)
    const obsGrid = {
        minX: Math.floor((obstacle.x - GRID_SIZE) / GRID_SIZE),
        maxX: Math.ceil((obstacle.x + obstacle.w + GRID_SIZE) / GRID_SIZE),
        minY: Math.floor((obstacle.y - GRID_SIZE) / GRID_SIZE),
        maxY: Math.ceil((obstacle.y + obstacle.h + GRID_SIZE) / GRID_SIZE)
    };

    const openList: Node[] = [];
    const closedSet = new Set<string>();

    openList.push(new Node(startGrid.x, startGrid.y));

    let closestNode = openList[0];
    let minH = Infinity;

    // Safety break
    let iterations = 0;
    const MAX_ITERATIONS = 500; 

    while (openList.length > 0 && iterations < MAX_ITERATIONS) {
        iterations++;

        // Sort by F cost
        openList.sort((a, b) => a.f - b.f);
        const current = openList.shift()!;

        // Check if reached destination (within 1 tile radius)
        if (Math.abs(current.x - endGrid.x) <= 1 && Math.abs(current.y - endGrid.y) <= 1) {
            const path: Point[] = [];
            let curr: Node | null = current;
            while (curr) {
                // Convert back to world coordinates (center of tile)
                path.push({ x: curr.x * GRID_SIZE + GRID_SIZE/2, y: curr.y * GRID_SIZE + GRID_SIZE/2 });
                curr = curr.parent;
            }
            return path.reverse(); // Start to End
        }

        closedSet.add(current.key);

        // Update closest node for fallback
        const dist = Math.abs(current.x - endGrid.x) + Math.abs(current.y - endGrid.y);
        if (dist < minH) {
            minH = dist;
            closestNode = current;
        }

        // Neighbors (8 directions)
        const dirs = [
            {x:0, y:-1}, {x:0, y:1}, {x:-1, y:0}, {x:1, y:0},
            {x:-1, y:-1}, {x:1, y:-1}, {x:-1, y:1}, {x:1, y:1}
        ];

        for (const dir of dirs) {
            const nx = current.x + dir.x;
            const ny = current.y + dir.y;
            const key = `${nx},${ny}`;

            // Bounds check
            if (nx < 0 || ny < 0 || nx * GRID_SIZE >= worldSize || ny * GRID_SIZE >= worldSize) continue;
            if (closedSet.has(key)) continue;

            // Obstacle Check (Base)
            // Allow start and end nodes to be "inside" obstacle logic slightly to prevent getting stuck
            const isStartOrEnd = (nx === startGrid.x && ny === startGrid.y) || (nx === endGrid.x && ny === endGrid.y);
            if (!isStartOrEnd && 
                nx >= obsGrid.minX && nx < obsGrid.maxX && 
                ny >= obsGrid.minY && ny < obsGrid.maxY) {
                continue;
            }

            const gScore = current.g + Math.sqrt(dir.x*dir.x + dir.y*dir.y);
            const existingNode = openList.find(n => n.key === key);

            if (!existingNode) {
                const hScore = Math.sqrt(Math.pow(nx - endGrid.x, 2) + Math.pow(ny - endGrid.y, 2));
                openList.push(new Node(nx, ny, gScore, hScore, current));
            } else if (gScore < existingNode.g) {
                existingNode.g = gScore;
                existingNode.parent = current;
            }
        }
    }

    // Fallback: return path to closest point found
    const path: Point[] = [];
    let curr: Node | null = closestNode;
    while (curr) {
        path.push({ x: curr.x * GRID_SIZE + GRID_SIZE/2, y: curr.y * GRID_SIZE + GRID_SIZE/2 });
        curr = curr.parent;
    }
    return path.reverse();
}

export class RectImpl implements Rect {
    constructor(
        public x: number,
        public y: number,
        public w: number,
        public h: number
    ) {}

    collidesWith(other: Rect): boolean {
        return (
            this.x < other.x + other.w &&
            this.x + this.w > other.x &&
            this.y < other.y + other.h &&
            this.y + this.h > other.y
        );
    }

    get center(): { x: number; y: number } {
        return {
            x: this.x + this.w / 2,
            y: this.y + this.h / 2,
        };
    }
}

export class Resource {
    rect: RectImpl;
    isCarried: boolean = false;
    isDeposited: boolean = false;
    color: string;

    constructor(x: number, y: number, size: number) {
        this.rect = new RectImpl(x, y, size, size);
        // Randomize resource color slightly for aesthetics
        const hue = Math.floor(Math.random() * 60) + 180; // Cyans/Blues
        this.color = `hsl(${hue}, 70%, 60%)`;
    }
}

export class Base {
    rect: RectImpl;
    slots: { x: number; y: number }[] = [];
    resourceSize: number;

    constructor(config: SimulationConfig) {
        this.resourceSize = config.RESOURCE_SIZE;
        const startPos = (config.WORLD_SIZE - config.BASE_START_SIZE) / 2;
        this.rect = new RectImpl(startPos, startPos, config.BASE_START_SIZE, config.BASE_START_SIZE);
        this._generateLayerSlots();
    }

    _generateLayerSlots() {
        this.slots = [];
        const r = this.resourceSize;
        // Top and Bottom perimeters
        for (let x = this.rect.x - r; x < this.rect.x + this.rect.w + r; x += r) {
            this.slots.push({ x, y: this.rect.y - r }); // Top
            this.slots.push({ x, y: this.rect.y + this.rect.h }); // Bottom
        }
        // Left and Right perimeters
        for (let y = this.rect.y; y < this.rect.y + this.rect.h; y += r) {
            this.slots.push({ x: this.rect.x - r, y }); // Left
            this.slots.push({ x: this.rect.x + this.rect.w, y }); // Right
        }
    }

    getPointsPerTick(): number {
        return Math.floor(this.rect.w * this.rect.h);
    }

    deposit(resource: Resource, agentPos: { x: number; y: number }) {
        if (this.slots.length === 0) return;

        // Find nearest gap
        let nearestIdx = 0;
        let minDist = Infinity;

        this.slots.forEach((slot, i) => {
            const dist = Math.sqrt(Math.pow(slot.x - agentPos.x, 2) + Math.pow(slot.y - agentPos.y, 2));
            if (dist < minDist) {
                minDist = dist;
                nearestIdx = i;
            }
        });

        const slot = this.slots.splice(nearestIdx, 1)[0];
        resource.rect.x = slot.x;
        resource.rect.y = slot.y;
        resource.isDeposited = true;
        resource.isCarried = false;

        if (this.slots.length === 0) {
            this._expandBase();
        }
    }

    _expandBase() {
        this.rect.x -= this.resourceSize;
        this.rect.y -= this.resourceSize;
        this.rect.w += this.resourceSize * 2;
        this.rect.h += this.resourceSize * 2;
        this._generateLayerSlots();
    }
}

export class Agent {
    rect: RectImpl;
    lastMove: { x: number; y: number };
    targetResource: Resource | null = null;
    carriedResource: Resource | null = null;
    state: AgentState = AgentState.SEARCH;
    id: string;

    // Pathfinding
    path: Point[] = [];
    pathIndex: number = 0;

    constructor(x: number, y: number, size: number, initialSpeed: number) {
        this.rect = new RectImpl(x, y, size, size);
        this.lastMove = { x: 0, y: initialSpeed };
        this.id = Math.random().toString(36).substr(2, 9);
    }

    _moveTowards(tx: number, ty: number, speed: number, wiggle: number) {
        const dx = tx - this.rect.x;
        const dy = ty - this.rect.y;

        // Normalize vector
        const dist = Math.sqrt(dx*dx + dy*dy);

        let mx = 0;
        let my = 0;

        if (dist > speed) {
            mx = (dx / dist) * speed;
            my = (dy / dist) * speed;
        } else {
            mx = dx;
            my = dy;
        }

        // Random movement noise (wiggle)
        if (wiggle > 0 && Math.random() < wiggle) {
             const dirs = [
                 {x: speed, y: 0}, {x: -speed, y: 0},
                 {x: 0, y: speed}, {x: 0, y: -speed}
             ];
             const randDir = dirs[Math.floor(Math.random() * dirs.length)];
             mx = randDir.x;
             my = randDir.y;
        }

        this.rect.x += mx;
        this.rect.y += my;
        this.lastMove = { x: mx, y: my };
    }

    update(world: SimulationEngine) {
        const { AGENT_SPEED, AGENT_LOS, WORLD_SIZE, AGENT_WIGGLE, PATHFINDING_MODE } = world.config;

        if (this.state === AgentState.SEARCH) {
            this.path = []; // Clear path

            // Patrol vertical
            this.rect.y += this.lastMove.y > 0 ? AGENT_SPEED : -AGENT_SPEED;
            this.lastMove.y = this.lastMove.y > 0 ? AGENT_SPEED : -AGENT_SPEED;

            // Apply slight random direction change during search too
             if (AGENT_WIGGLE > 0 && Math.random() < AGENT_WIGGLE * 0.1) {
                 this.lastMove.y = -this.lastMove.y;
             }

            // Use internal height (this.rect.h) for bounds check to allow mixed agent sizes
            if (this.rect.y <= 0 || this.rect.y >= WORLD_SIZE - this.rect.h) {
                this.lastMove.y = -this.lastMove.y;
            }

            // --- LOS Check with Inter-Agent Communication ---
            // Cache current agent center
            const cx = this.rect.x + this.rect.w / 2;
            const cy = this.rect.y + this.rect.h / 2;
            const losSq = AGENT_LOS * AGENT_LOS;

            for (const res of world.resources) {
                if (!res.isCarried && !res.isDeposited) {
                    const rcx = res.rect.x + res.rect.w / 2;
                    const rcy = res.rect.y + res.rect.h / 2;

                    // Check distance to resource
                    const distSq = (cx - rcx) ** 2 + (cy - rcy) ** 2;

                    if (distSq <= losSq) {
                        // Resource is visible. 
                        // Now check if any neighbor (within LOS) has already claimed it.
                        let isClaimedByNeighbor = false;

                        for (const otherAgent of world.agents) {
                            if (otherAgent === this) continue;

                            // Check if other agent is targeting this resource
                            if (otherAgent.targetResource === res) {
                                // Agent detected targeting this resource.
                                // Is this agent within our LOS?
                                const ocx = otherAgent.rect.x + otherAgent.rect.w / 2;
                                const ocy = otherAgent.rect.y + otherAgent.rect.h / 2;
                                const distToAgentSq = (cx - ocx) ** 2 + (cy - ocy) ** 2;

                                if (distToAgentSq <= losSq) {
                                    isClaimedByNeighbor = true;
                                    break; 
                                }
                            }
                        }

                        if (!isClaimedByNeighbor) {
                            this.targetResource = res;
                            this.state = AgentState.APPROACH;
                            this.path = []; // Reset path when target found
                            break;
                        }
                    }
                }
            }
        } else if (this.state === AgentState.APPROACH) {
            if (!this.targetResource || this.targetResource.isCarried || this.targetResource.isDeposited) {
                this.targetResource = null;
                this.state = AgentState.SEARCH;
                this.path = [];
                return;
            }

            // Logic Switch
            if (PATHFINDING_MODE === PathfindingMode.A_STAR) {
                if (this.path.length === 0) {
                    this.path = findPath(this.rect, this.targetResource.rect, world.base.rect, WORLD_SIZE);
                    this.pathIndex = 0;
                }

                // Follow Path
                if (this.pathIndex < this.path.length) {
                    const nextPoint = this.path[this.pathIndex];
                    this._moveTowards(nextPoint.x, nextPoint.y, AGENT_SPEED, 0); // No wiggle on path

                    // Check if reached point
                    if (Math.abs(this.rect.x - nextPoint.x) < AGENT_SPEED && Math.abs(this.rect.y - nextPoint.y) < AGENT_SPEED) {
                        this.pathIndex++;
                    }
                } else {
                    // Reached end of path, move direct to target (final approach)
                     this._moveTowards(this.targetResource.rect.x, this.targetResource.rect.y, AGENT_SPEED, 0);
                }
            } else {
                // DIRECT Mode
                this._moveTowards(this.targetResource.rect.x, this.targetResource.rect.y, AGENT_SPEED, AGENT_WIGGLE);
            }

            if (this.rect.collidesWith(this.targetResource.rect)) {
                this.carriedResource = this.targetResource;
                this.carriedResource.isCarried = true;
                this.targetResource = null;
                this.state = AgentState.RETURN;
                this.path = []; // Reset path for return trip
            }
        } else if (this.state === AgentState.RETURN) {
            if (!this.carriedResource) {
                this.state = AgentState.SEARCH;
                this.path = [];
                return;
            }

            const bc = world.base.rect.center;
            const targetX = bc.x - 8;
            const targetY = bc.y - 8;

            // In return, we just go direct unless A* is super requested, 
            // but usually return is direct to base perimeter.
            // Actually, if we are on the wrong side of the base, we might clip through it if the base is huge.
            // But 'Return' means we WANT to hit the base.
            // A* is useful if there were OTHER obstacles. 
            // For now, let's stick to direct for return to ensure they hit the base, 
            // OR use A* to get to the edge if we wanted to be fancy, but collision triggers deposit.

            // Just use direct with wiggle for return to simulate "hauling".
             this._moveTowards(targetX, targetY, AGENT_SPEED, AGENT_WIGGLE);

            // Carry logic visual
            if (Math.abs(this.lastMove.y) > Math.abs(this.lastMove.x)) {
                if (this.lastMove.y < 0) { // Up
                    this.carriedResource.rect.x = this.rect.x + 4;
                    this.carriedResource.rect.y = this.rect.y - 8;
                } else { // Down
                    this.carriedResource.rect.x = this.rect.x + 4;
                    this.carriedResource.rect.y = this.rect.y + 16;
                }
            } else {
                if (this.lastMove.x < 0) { // Left
                    this.carriedResource.rect.x = this.rect.x - 8;
                    this.carriedResource.rect.y = this.rect.y + 4;
                } else { // Right
                    this.carriedResource.rect.x = this.rect.x + 16;
                    this.carriedResource.rect.y = this.rect.y + 4;
                }
            }

            if (this.rect.collidesWith(world.base.rect)) {
                world.base.deposit(this.carriedResource!, { x: this.rect.x, y: this.rect.y });
                this.carriedResource = null;
                this.state = AgentState.SEARCH;
                this.path = [];
            }
        }

        // World Bounds Clamp
        this.rect.x = Math.max(0, Math.min(WORLD_SIZE - this.rect.w, this.rect.x));
        this.rect.y = Math.max(0, Math.min(WORLD_SIZE - this.rect.h, this.rect.y));
    }
}

export class SimulationEngine {
    config: SimulationConfig;
    base: Base;
    agents: Agent[] = [];
    resources: Resource[] = [];
    totalPoints: number = 0;
    spawnAccumulator: number = 0;
    tickCount: number = 0;

    constructor(config: SimulationConfig = DefaultConfig) {
        this.config = { ...config };
        this.base = new Base(this.config);
        this._initializeEntities();
    }

    _initializeEntities() {
        for (let i = 0; i < this.config.INITIAL_RESOURCES; i++) this._spawnResource();
        for (let i = 0; i < this.config.INITIAL_AGENTS; i++) this._spawnAgent();
    }

    _spawnResource() {
        this.resources.push(new Resource(
            Math.floor(Math.random() * (this.config.WORLD_SIZE - this.config.RESOURCE_SIZE)),
            Math.floor(Math.random() * (this.config.WORLD_SIZE - this.config.RESOURCE_SIZE)),
            this.config.RESOURCE_SIZE
        ));
    }

    _spawnAgent() {
        const br = this.base.rect;
        const side = ['N', 'S', 'E', 'W'][Math.floor(Math.random() * 4)];
        let x = 0, y = 0;
        const size = this.config.AGENT_SIZE;

        if (side === 'N') { x = br.x + Math.random() * br.w; y = br.y - size; }
        else if (side === 'S') { x = br.x + Math.random() * br.w; y = br.y + br.h; }
        else if (side === 'E') { x = br.x + br.w; y = br.y + Math.random() * br.h; }
        else { x = br.x - size; y = br.y + Math.random() * br.h; }

        this.agents.push(new Agent(x, y, size, this.config.AGENT_SPEED));
    }

    tick() {
        this.tickCount++;

        // 1. Spawn Resource (Probabilistic + Count)
        const spawnRate = this.config.RESOURCE_SPAWN_CHANCE;
        const count = Math.floor(spawnRate);
        const remainder = spawnRate - count;

        for(let i=0; i<count; i++) this._spawnResource();
        if (Math.random() < remainder) {
            this._spawnResource();
        }

        // 2. Points & Agent Spawn
        // Points scaled by multiplier
        const pointsThisTick = this.base.getPointsPerTick() * this.config.BASE_POINT_MULTIPLIER;
        this.totalPoints += pointsThisTick;
        this.spawnAccumulator += pointsThisTick;

        if (this.spawnAccumulator >= this.config.AGENT_SPAWN_THRESHOLD) {
            if (this.agents.length < this.config.MAX_AGENTS) {
                this._spawnAgent();
            }
            this.spawnAccumulator -= this.config.AGENT_SPAWN_THRESHOLD;
        }

        // 3. Update Agents
        this.agents.forEach(agent => agent.update(this));
    }
}

import { AgentState, Rect, SimulationConfig, PathfindingMode } from '../types';

export const DefaultConfig: SimulationConfig = {
    WORLD_SIZE: 1024,
    AGENT_SPEED: 3,
    AGENT_LOS: 176,
    BASE_START_SIZE: 64,
    RESOURCE_SIZE: 8,
    AGENT_SIZE: 8,
    INITIAL_AGENTS: 3,
    INITIAL_RESOURCES: 64,
    AGENT_SPAWN_THRESHOLD: 262144,
    RESOURCE_SPAWN_CHANCE: 0.1,
    BASE_POINT_MULTIPLIER: 1.0,
    AGENT_WIGGLE: 0,
    MAX_AGENTS: 5000,
    PATHFINDING_MODE: PathfindingMode.A_STAR
};

interface Point {
    x: number;
    y: number;
}

// A* Implementation
const GRID_SIZE = 32;

class Node {
    constructor(
        public x: number,
        public y: number,
        public g: number = 0,
        public h: number = 0,
        public parent: Node | null = null
    ) {}

    get f() { return this.g + this.h; }
    get key() { return `${this.x},${this.y}`; }
}

function findPath(start: Point, end: Point, obstacle: Rect, worldSize: number): Point[] {
    const startGrid = { x: Math.floor(start.x / GRID_SIZE), y: Math.floor(start.y / GRID_SIZE) };
    const endGrid = { x: Math.floor(end.x / GRID_SIZE), y: Math.floor(end.y / GRID_SIZE) };

    // Convert obstacle to grid bounds (with padding)
    const obsGrid = {
        minX: Math.floor((obstacle.x - GRID_SIZE) / GRID_SIZE),
        maxX: Math.ceil((obstacle.x + obstacle.w + GRID_SIZE) / GRID_SIZE),
        minY: Math.floor((obstacle.y - GRID_SIZE) / GRID_SIZE),
        maxY: Math.ceil((obstacle.y + obstacle.h + GRID_SIZE) / GRID_SIZE)
    };

    const openList: Node[] = [];
    const closedSet = new Set<string>();

    openList.push(new Node(startGrid.x, startGrid.y));

    let closestNode = openList[0];
    let minH = Infinity;

    // Safety break
    let iterations = 0;
    const MAX_ITERATIONS = 500; 

    while (openList.length > 0 && iterations < MAX_ITERATIONS) {
        iterations++;

        // Sort by F cost
        openList.sort((a, b) => a.f - b.f);
        const current = openList.shift()!;

        // Check if reached destination (within 1 tile radius)
        if (Math.abs(current.x - endGrid.x) <= 1 && Math.abs(current.y - endGrid.y) <= 1) {
            const path: Point[] = [];
            let curr: Node | null = current;
            while (curr) {
                // Convert back to world coordinates (center of tile)
                path.push({ x: curr.x * GRID_SIZE + GRID_SIZE/2, y: curr.y * GRID_SIZE + GRID_SIZE/2 });
                curr = curr.parent;
            }
            return path.reverse(); // Start to End
        }

        closedSet.add(current.key);

        // Update closest node for fallback
        const dist = Math.abs(current.x - endGrid.x) + Math.abs(current.y - endGrid.y);
        if (dist < minH) {
            minH = dist;
            closestNode = current;
        }

        // Neighbors (8 directions)
        const dirs = [
            {x:0, y:-1}, {x:0, y:1}, {x:-1, y:0}, {x:1, y:0},
            {x:-1, y:-1}, {x:1, y:-1}, {x:-1, y:1}, {x:1, y:1}
        ];

        for (const dir of dirs) {
            const nx = current.x + dir.x;
            const ny = current.y + dir.y;
            const key = `${nx},${ny}`;

            // Bounds check
            if (nx < 0 || ny < 0 || nx * GRID_SIZE >= worldSize || ny * GRID_SIZE >= worldSize) continue;
            if (closedSet.has(key)) continue;

            // Obstacle Check (Base)
            // Allow start and end nodes to be "inside" obstacle logic slightly to prevent getting stuck
            const isStartOrEnd = (nx === startGrid.x && ny === startGrid.y) || (nx === endGrid.x && ny === endGrid.y);
            if (!isStartOrEnd && 
                nx >= obsGrid.minX && nx < obsGrid.maxX && 
                ny >= obsGrid.minY && ny < obsGrid.maxY) {
                continue;
            }

            const gScore = current.g + Math.sqrt(dir.x*dir.x + dir.y*dir.y);
            const existingNode = openList.find(n => n.key === key);

            if (!existingNode) {
                const hScore = Math.sqrt(Math.pow(nx - endGrid.x, 2) + Math.pow(ny - endGrid.y, 2));
                openList.push(new Node(nx, ny, gScore, hScore, current));
            } else if (gScore < existingNode.g) {
                existingNode.g = gScore;
                existingNode.parent = current;
            }
        }
    }

    // Fallback: return path to closest point found
    const path: Point[] = [];
    let curr: Node | null = closestNode;
    while (curr) {
        path.push({ x: curr.x * GRID_SIZE + GRID_SIZE/2, y: curr.y * GRID_SIZE + GRID_SIZE/2 });
        curr = curr.parent;
    }
    return path.reverse();
}

export class RectImpl implements Rect {
    constructor(
        public x: number,
        public y: number,
        public w: number,
        public h: number
    ) {}

    collidesWith(other: Rect): boolean {
        return (
            this.x < other.x + other.w &&
            this.x + this.w > other.x &&
            this.y < other.y + other.h &&
            this.y + this.h > other.y
        );
    }

    get center(): { x: number; y: number } {
        return {
            x: this.x + this.w / 2,
            y: this.y + this.h / 2,
        };
    }
}

export class Resource {
    rect: RectImpl;
    isCarried: boolean = false;
    isDeposited: boolean = false;
    color: string;

    constructor(x: number, y: number, size: number) {
        this.rect = new RectImpl(x, y, size, size);
        // Randomize resource color slightly for aesthetics
        const hue = Math.floor(Math.random() * 60) + 180; // Cyans/Blues
        this.color = `hsl(${hue}, 70%, 60%)`;
    }
}

export class Base {
    rect: RectImpl;
    slots: { x: number; y: number }[] = [];
    resourceSize: number;

    constructor(config: SimulationConfig) {
        this.resourceSize = config.RESOURCE_SIZE;
        const startPos = (config.WORLD_SIZE - config.BASE_START_SIZE) / 2;
        this.rect = new RectImpl(startPos, startPos, config.BASE_START_SIZE, config.BASE_START_SIZE);
        this._generateLayerSlots();
    }

    _generateLayerSlots() {
        this.slots = [];
        const r = this.resourceSize;
        // Top and Bottom perimeters
        for (let x = this.rect.x - r; x < this.rect.x + this.rect.w + r; x += r) {
            this.slots.push({ x, y: this.rect.y - r }); // Top
            this.slots.push({ x, y: this.rect.y + this.rect.h }); // Bottom
        }
        // Left and Right perimeters
        for (let y = this.rect.y; y < this.rect.y + this.rect.h; y += r) {
            this.slots.push({ x: this.rect.x - r, y }); // Left
            this.slots.push({ x: this.rect.x + this.rect.w, y }); // Right
        }
    }

    getPointsPerTick(): number {
        return Math.floor(this.rect.w * this.rect.h);
    }

    deposit(resource: Resource, agentPos: { x: number; y: number }) {
        if (this.slots.length === 0) return;

        // Find nearest gap
        let nearestIdx = 0;
        let minDist = Infinity;

        this.slots.forEach((slot, i) => {
            const dist = Math.sqrt(Math.pow(slot.x - agentPos.x, 2) + Math.pow(slot.y - agentPos.y, 2));
            if (dist < minDist) {
                minDist = dist;
                nearestIdx = i;
            }
        });

        const slot = this.slots.splice(nearestIdx, 1)[0];
        resource.rect.x = slot.x;
        resource.rect.y = slot.y;
        resource.isDeposited = true;
        resource.isCarried = false;

        if (this.slots.length === 0) {
            this._expandBase();
        }
    }

    _expandBase() {
        this.rect.x -= this.resourceSize;
        this.rect.y -= this.resourceSize;
        this.rect.w += this.resourceSize * 2;
        this.rect.h += this.resourceSize * 2;
        this._generateLayerSlots();
    }
}

export class Agent {
    rect: RectImpl;
    lastMove: { x: number; y: number };
    targetResource: Resource | null = null;
    carriedResource: Resource | null = null;
    state: AgentState = AgentState.SEARCH;
    id: string;

    // Pathfinding
    path: Point[] = [];
    pathIndex: number = 0;

    constructor(x: number, y: number, size: number, initialSpeed: number) {
        this.rect = new RectImpl(x, y, size, size);
        this.lastMove = { x: 0, y: initialSpeed };
        this.id = Math.random().toString(36).substr(2, 9);
    }

    _moveTowards(tx: number, ty: number, speed: number, wiggle: number) {
        const dx = tx - this.rect.x;
        const dy = ty - this.rect.y;

        // Normalize vector
        const dist = Math.sqrt(dx*dx + dy*dy);

        let mx = 0;
        let my = 0;

        if (dist > speed) {
            mx = (dx / dist) * speed;
            my = (dy / dist) * speed;
        } else {
            mx = dx;
            my = dy;
        }

        // Random movement noise (wiggle)
        if (wiggle > 0 && Math.random() < wiggle) {
             const dirs = [
                 {x: speed, y: 0}, {x: -speed, y: 0},
                 {x: 0, y: speed}, {x: 0, y: -speed}
             ];
             const randDir = dirs[Math.floor(Math.random() * dirs.length)];
             mx = randDir.x;
             my = randDir.y;
        }

        this.rect.x += mx;
        this.rect.y += my;
        this.lastMove = { x: mx, y: my };
    }

    update(world: SimulationEngine) {
        const { AGENT_SPEED, AGENT_LOS, WORLD_SIZE, AGENT_WIGGLE, PATHFINDING_MODE } = world.config;

        if (this.state === AgentState.SEARCH) {
            this.path = []; // Clear path

            // Patrol vertical
            this.rect.y += this.lastMove.y > 0 ? AGENT_SPEED : -AGENT_SPEED;
            this.lastMove.y = this.lastMove.y > 0 ? AGENT_SPEED : -AGENT_SPEED;

            // Apply slight random direction change during search too
             if (AGENT_WIGGLE > 0 && Math.random() < AGENT_WIGGLE * 0.1) {
                 this.lastMove.y = -this.lastMove.y;
             }

            // Use internal height (this.rect.h) for bounds check to allow mixed agent sizes
            if (this.rect.y <= 0 || this.rect.y >= WORLD_SIZE - this.rect.h) {
                this.lastMove.y = -this.lastMove.y;
            }

            // --- LOS Check with Inter-Agent Communication ---
            // Cache current agent center
            const cx = this.rect.x + this.rect.w / 2;
            const cy = this.rect.y + this.rect.h / 2;
            const losSq = AGENT_LOS * AGENT_LOS;

            for (const res of world.resources) {
                if (!res.isCarried && !res.isDeposited) {
                    const rcx = res.rect.x + res.rect.w / 2;
                    const rcy = res.rect.y + res.rect.h / 2;

                    // Check distance to resource
                    const distSq = (cx - rcx) ** 2 + (cy - rcy) ** 2;

                    if (distSq <= losSq) {
                        // Resource is visible. 
                        // Now check if any neighbor (within LOS) has already claimed it.
                        let isClaimedByNeighbor = false;

                        for (const otherAgent of world.agents) {
                            if (otherAgent === this) continue;

                            // Check if other agent is targeting this resource
                            if (otherAgent.targetResource === res) {
                                // Agent detected targeting this resource.
                                // Is this agent within our LOS?
                                const ocx = otherAgent.rect.x + otherAgent.rect.w / 2;
                                const ocy = otherAgent.rect.y + otherAgent.rect.h / 2;
                                const distToAgentSq = (cx - ocx) ** 2 + (cy - ocy) ** 2;

                                if (distToAgentSq <= losSq) {
                                    isClaimedByNeighbor = true;
                                    break; 
                                }
                            }
                        }

                        if (!isClaimedByNeighbor) {
                            this.targetResource = res;
                            this.state = AgentState.APPROACH;
                            this.path = []; // Reset path when target found
                            break;
                        }
                    }
                }
            }
        } else if (this.state === AgentState.APPROACH) {
            if (!this.targetResource || this.targetResource.isCarried || this.targetResource.isDeposited) {
                this.targetResource = null;
                this.state = AgentState.SEARCH;
                this.path = [];
                return;
            }

            // Logic Switch
            if (PATHFINDING_MODE === PathfindingMode.A_STAR) {
                if (this.path.length === 0) {
                    this.path = findPath(this.rect, this.targetResource.rect, world.base.rect, WORLD_SIZE);
                    this.pathIndex = 0;
                }

                // Follow Path
                if (this.pathIndex < this.path.length) {
                    const nextPoint = this.path[this.pathIndex];
                    this._moveTowards(nextPoint.x, nextPoint.y, AGENT_SPEED, 0); // No wiggle on path

                    // Check if reached point
                    if (Math.abs(this.rect.x - nextPoint.x) < AGENT_SPEED && Math.abs(this.rect.y - nextPoint.y) < AGENT_SPEED) {
                        this.pathIndex++;
                    }
                } else {
                    // Reached end of path, move direct to target (final approach)
                     this._moveTowards(this.targetResource.rect.x, this.targetResource.rect.y, AGENT_SPEED, 0);
                }
            } else {
                // DIRECT Mode
                this._moveTowards(this.targetResource.rect.x, this.targetResource.rect.y, AGENT_SPEED, AGENT_WIGGLE);
            }

            if (this.rect.collidesWith(this.targetResource.rect)) {
                this.carriedResource = this.targetResource;
                this.carriedResource.isCarried = true;
                this.targetResource = null;
                this.state = AgentState.RETURN;
                this.path = []; // Reset path for return trip
            }
        } else if (this.state === AgentState.RETURN) {
            if (!this.carriedResource) {
                this.state = AgentState.SEARCH;
                this.path = [];
                return;
            }

            const bc = world.base.rect.center;
            const targetX = bc.x - 8;
            const targetY = bc.y - 8;

            // In return, we just go direct unless A* is super requested, 
            // but usually return is direct to base perimeter.
            // Actually, if we are on the wrong side of the base, we might clip through it if the base is huge.
            // But 'Return' means we WANT to hit the base.
            // A* is useful if there were OTHER obstacles. 
            // For now, let's stick to direct for return to ensure they hit the base, 
            // OR use A* to get to the edge if we wanted to be fancy, but collision triggers deposit.

            // Just use direct with wiggle for return to simulate "hauling".
             this._moveTowards(targetX, targetY, AGENT_SPEED, AGENT_WIGGLE);

            // Carry logic visual
            if (Math.abs(this.lastMove.y) > Math.abs(this.lastMove.x)) {
                if (this.lastMove.y < 0) { // Up
                    this.carriedResource.rect.x = this.rect.x + 4;
                    this.carriedResource.rect.y = this.rect.y - 8;
                } else { // Down
                    this.carriedResource.rect.x = this.rect.x + 4;
                    this.carriedResource.rect.y = this.rect.y + 16;
                }
            } else {
                if (this.lastMove.x < 0) { // Left
                    this.carriedResource.rect.x = this.rect.x - 8;
                    this.carriedResource.rect.y = this.rect.y + 4;
                } else { // Right
                    this.carriedResource.rect.x = this.rect.x + 16;
                    this.carriedResource.rect.y = this.rect.y + 4;
                }
            }

            if (this.rect.collidesWith(world.base.rect)) {
                world.base.deposit(this.carriedResource!, { x: this.rect.x, y: this.rect.y });
                this.carriedResource = null;
                this.state = AgentState.SEARCH;
                this.path = [];
            }
        }

        // Resolve Collisions (Basic separation)
        this._resolveCollisions(world);

        // World Bounds Clamp
        this.rect.x = Math.max(0, Math.min(WORLD_SIZE - this.rect.w, this.rect.x));
        this.rect.y = Math.max(0, Math.min(WORLD_SIZE - this.rect.h, this.rect.y));
    }

    _resolveCollisions(world: SimulationEngine) {
        const GRID_CELL = 32;
        const cols = Math.ceil(world.config.WORLD_SIZE / GRID_CELL);

        const cx = Math.floor((this.rect.x + this.rect.w/2) / GRID_CELL);
        const cy = Math.floor((this.rect.y + this.rect.h/2) / GRID_CELL);

        // Check 3x3 area
        for (let y = cy - 1; y <= cy + 1; y++) {
            for (let x = cx - 1; x <= cx + 1; x++) {
                if (x < 0 || y < 0 || x >= cols) continue; // Boundary check approx (assuming rows similar)

                const idx = y * cols + x;
                // Safety check for grid bounds
                if (idx < 0 || idx >= world.agentGrid.length) continue;

                const cell = world.agentGrid[idx];
                if (cell) {
                    for (const other of cell) {
                        if (other === this) continue;
                        if (this.rect.collidesWith(other.rect)) {
                            // Simple separation vector
                            const dx = (this.rect.x + this.rect.w/2) - (other.rect.x + other.rect.w/2);
                            const dy = (this.rect.y + this.rect.h/2) - (other.rect.y + other.rect.h/2);
                            const dist = Math.sqrt(dx*dx + dy*dy) || 0.001;

                            // Push away
                            const pushForce = 0.5; // Soft collision strength
                            this.rect.x += (dx / dist) * pushForce;
                            this.rect.y += (dy / dist) * pushForce;
                        }
                    }
                }
            }
        }
    }
}

export class SimulationEngine {
    config: SimulationConfig;
    base: Base;
    agents: Agent[] = [];
    resources: Resource[] = [];
    agentGrid: Agent[][] = []; // Spatial partitioning for collisions
    totalPoints: number = 0;
    spawnAccumulator: number = 0;
    tickCount: number = 0;

    constructor(config: SimulationConfig = DefaultConfig) {
        this.config = { ...config };
        this.base = new Base(this.config);
        this._initializeEntities();
    }

    _initializeEntities() {
        for (let i = 0; i < this.config.INITIAL_RESOURCES; i++) this._spawnResource();
        for (let i = 0; i < this.config.INITIAL_AGENTS; i++) this._spawnAgent();
    }

    _spawnResource() {
        this.resources.push(new Resource(
            Math.floor(Math.random() * (this.config.WORLD_SIZE - this.config.RESOURCE_SIZE)),
            Math.floor(Math.random() * (this.config.WORLD_SIZE - this.config.RESOURCE_SIZE)),
            this.config.RESOURCE_SIZE
        ));
    }

    _spawnAgent() {
        const br = this.base.rect;
        const side = ['N', 'S', 'E', 'W'][Math.floor(Math.random() * 4)];
        let x = 0, y = 0;
        const size = this.config.AGENT_SIZE;

        if (side === 'N') { x = br.x + Math.random() * br.w; y = br.y - size; }
        else if (side === 'S') { x = br.x + Math.random() * br.w; y = br.y + br.h; }
        else if (side === 'E') { x = br.x + br.w; y = br.y + Math.random() * br.h; }
        else { x = br.x - size; y = br.y + Math.random() * br.h; }

        this.agents.push(new Agent(x, y, size, this.config.AGENT_SPEED));
    }

    tick() {
        this.tickCount++;

        // 1. Rebuild Spatial Grid for Collision
        // Using a 32px grid size
        const GRID_CELL = 32;
        const cols = Math.ceil(this.config.WORLD_SIZE / GRID_CELL);
        const rows = Math.ceil(this.config.WORLD_SIZE / GRID_CELL);

        // Reset grid
        this.agentGrid = new Array(cols * rows);
        for(let i=0; i<this.agentGrid.length; i++) this.agentGrid[i] = [];

        // Populate grid
        for (const agent of this.agents) {
            const cx = Math.floor((agent.rect.x + agent.rect.w/2) / GRID_CELL);
            const cy = Math.floor((agent.rect.y + agent.rect.h/2) / GRID_CELL);

            // Bounds check for grid assignment
            if (cx >= 0 && cx < cols && cy >= 0 && cy < rows) {
                const idx = cy * cols + cx;
                this.agentGrid[idx].push(agent);
            }
        }

        // 2. Spawn Resource (Probabilistic + Count)
        const spawnRate = this.config.RESOURCE_SPAWN_CHANCE;
        const count = Math.floor(spawnRate);
        const remainder = spawnRate - count;

        for(let i=0; i<count; i++) this._spawnResource();
        if (Math.random() < remainder) {
            this._spawnResource();
        }

        // 3. Points & Agent Spawn
        // Points scaled by multiplier
        const pointsThisTick = this.base.getPointsPerTick() * this.config.BASE_POINT_MULTIPLIER;
        this.totalPoints += pointsThisTick;
        this.spawnAccumulator += pointsThisTick;

        if (this.spawnAccumulator >= this.config.AGENT_SPAWN_THRESHOLD) {
            if (this.agents.length < this.config.MAX_AGENTS) {
                this._spawnAgent();
            }
            this.spawnAccumulator -= this.config.AGENT_SPAWN_THRESHOLD;
        }

        // 4. Update Agents
        this.agents.forEach(agent => agent.update(this));
    }
}

